import socket
import json
from collections import namedtuple
import threading

Player = namedtuple('Player', ['id', 'position', 'health'])
Gamestate = namedtuple('Gamestate', ['players'])

class GameServer:
    def __init__(self, host='localhost', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((host, port))
        self.server_socket.listen()
        self.clients = []
        self.players = {}
        self.lock = threading.Lock()

    def broadcast(self, message):
        with self.lock:
            for client in self.clients:
                try:
                    client.sendall(message.encode('utf-8'))
                except Exception as e:
                    print(f"Failed to send data to {client.getpeername()}: {e}")
                    client.close()
                    self.clients.remove(client)

    def handle_client(self, client_socket):
        while True:
            try:
                data = client_socket.recv(1024).decode('utf-8')
                if not data:
                    break
                # Process client commands if needed
            except Exception as e:
                print(f"Client {client_socket.getpeername()} disconnected: {e}")
                break

        with self.lock:
            self.clients.remove(client_socket)
            client_socket.close()

    def send_game_state(self):
        while True:
            gamestate = Gamestate(players=list(self.players.values()))
            gamestate_json = json.dumps(gamestate._asdict())
            self.broadcast(gamestate_json)
            # Sleep for a tick duration or other timing logic

    def start(self):
        print("Server started, waiting for connections...")
        threading.Thread(target=self.send_game_state).start()
        while True:
            client_socket, addr = self.server_socket.accept()
            print(f"Connection from {addr}")
            with self.lock:
                self.clients.append(client_socket)
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

if __name__ == "__main__":
    server = GameServer()
    server.start()